[asy]

pair A,B,C,D;

A = (0,0);

B = (0,12);

C = (9,0);

D = (4,0);

draw(D--B--C--A--B);

draw(rightanglemark(D,A,B,20));

label("$A$",A,SW);

label("$B$",B,N);

label("$D$",D,S);

label("$C$",C,SE);

